// Authentication
export const getCurrentUserIdFromStorage = (): string | null => {
  if (isServer) return null;
  return localStorage.getItem('currentUserId');
};

export const setCurrentUserIdInStorage = (userId: string) => {
  if (isServer) return;
  localStorage.setItem('currentUserId', userId);
};

export const clearCurrentUserIdFromStorage = () => {
  if (isServer) return;
  localStorage.removeItem('currentUserId');
};

export const loginUser = (id: string, password: string): User | null => {
  if (id === 'admin' && password === 'ADMIN@2026') {
    const adminUser: User = {
      id: 'admin',
      name: 'System Administrator',
      email: 'admin@school.edu',
      password: 'ADMIN@2026',
      role: 'admin'
    };
    setCurrentUserIdInStorage('admin');
    return adminUser;
  }

  const users = getUsers();
  const user = users.find(u => u.id === id && u.password === password);
  if (user) {
    setCurrentUserIdInStorage(user.id);
    return user;
  }
  return null;
};
